import{_ as o,o as a,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Anti Yo-Yo System","description":"","frontmatter":{},"headers":[],"relativePath":"ru/advanced/anti-yoyo.md","filePath":"ru/advanced/anti-yoyo.md"}'),s={name:"ru/advanced/anti-yoyo.md"};function l(n,t,c,r,p,d){return a(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="anti-yo-yo-system" tabindex="-1"><i class="ph ph-arrows-clockwise"></i> Anti Yo-Yo System <a class="header-anchor" href="#anti-yo-yo-system" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-arrows-clockwise&quot;&gt;&lt;/i&gt; Anti Yo-Yo System&quot;">​</a></h1><p>Одной из самых раздражающих проблем систем динамического масштабирования является <strong>эффект «Йо-Йо»</strong> (или пинг-понг качества).</p><h2 id="суть-проблемы" tabindex="-1"><i class="ph ph-warning-circle"></i> Суть проблемы <a class="header-anchor" href="#суть-проблемы" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-warning-circle&quot;&gt;&lt;/i&gt; Суть проблемы&quot;">​</a></h2><p>Без умного контроля система попадает в бесконечную петлю:</p><ol><li>FPS падает из-за тяжелой сцены.</li><li>Плагин снижает качество графики (например, урезает разрешение).</li><li>Нагрузка падает, FPS вырастает выше нормы.</li><li>Плагин решает, что появились свободные ресурсы, и возвращает качество графики обратно на максимум.</li><li>FPS снова падает. Цикл повторяется.</li></ol><p>В результате игрок видит постоянное визуальное мерцание: тени то появляются, то исчезают, а картинка каждую секунду &quot;прыгает&quot; от мыльной к четкой.</p><h2 id="решение-webap-система-штрафов" tabindex="-1"><i class="ph ph-shield-check"></i> Решение WebAP: Система штрафов <a class="header-anchor" href="#решение-webap-система-штрафов" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-shield-check&quot;&gt;&lt;/i&gt; Решение WebAP: Система штрафов&quot;">​</a></h2><p>Мы полностью искоренили эту проблему, внедрив концепцию штрафов (Penalty Lockout). Она строится на двух параметрах из настроек плагина.</p><p>Когда плагин <em>повышает</em> качество графики, он запускает скрытый таймер — <strong>Detection Window</strong> (например, 15 секунд). В течение этого времени Индексатор пристально следит за стабильностью кадра.</p><p>Если в это окно FPS внезапно проседает, система делает однозначный вывод: <em>«Предыдущее повышение графики было ошибкой, устройство не тянет этот уровень на длинной дистанции»</em>.</p><p><strong>Срабатывает штраф:</strong></p><ol><li>Плагин немедленно снижает качество обратно.</li><li>Накладывается жесткая блокировка <strong>Penalty Lockout Duration</strong> (например, на 60 секунд).</li><li>В течение этой минуты плагину <strong>категорически запрещено</strong> пытаться снова повысить качество графики, даже если FPS улетит в небеса и процессор будет простаивать.</li></ol><div class="tip custom-block"><p class="custom-block-title">Длительная блокировка (Session Lock)</p><p>Если динамика вашей игры такова, что скачки нагрузки происходят волнами, и вы не хотите, чтобы качество вообще пыталось восстановиться после первого же падения, просто укажите очень большое значение в поле <strong>Penalty Lockout Duration</strong> (например, <code>600</code> для 10 минут или <code>3600</code> для часа). Это фактически зафиксирует графику на стабильно низком уровне до конца игровой сессии.</p></div><div class="info custom-block"><p class="custom-block-title">Приоритет плавности</p><p>Штраф блокирует только попытки улучшить картинку. Если игрок зайдет в еще более тяжелую сцену и FPS упадет ниже критического уровня, плагин всё равно сможет экстренно снизить качество дальше. Система всегда ставит плавность геймплея выше визуальных эффектов.</p></div>',14)])])}const m=o(s,[["render",l]]);export{u as __pageData,m as default};
